/**
 * Parse rate limit information from response headers
 */
function parseRateLimitHeaders(response) {
    const info = {};
    // Parse Retry-After header (can be seconds or HTTP date)
    const retryAfter = response.headers.get("retry-after");
    if (retryAfter) {
        const seconds = parseInt(retryAfter, 10);
        if (!isNaN(seconds)) {
            info.retryAfterMs = seconds * 1000;
        }
        else {
            // Try parsing as HTTP date
            const date = Date.parse(retryAfter);
            if (!isNaN(date)) {
                info.retryAfterMs = Math.max(0, date - Date.now());
            }
        }
    }
    // Parse X-RateLimit-Reset (Unix timestamp)
    const reset = response.headers.get("x-ratelimit-reset");
    if (reset) {
        const resetTimestamp = parseInt(reset, 10);
        if (!isNaN(resetTimestamp)) {
            // Convert to ms (timestamps are usually in seconds)
            info.resetMs = resetTimestamp * 1000;
            // If no Retry-After, calculate wait time from reset
            if (info.retryAfterMs === undefined) {
                info.retryAfterMs = Math.max(0, info.resetMs - Date.now());
            }
        }
    }
    // Parse X-RateLimit-Limit
    const limit = response.headers.get("x-ratelimit-limit");
    if (limit) {
        const limitNum = parseInt(limit, 10);
        if (!isNaN(limitNum)) {
            info.limit = limitNum;
        }
    }
    // Parse X-RateLimit-Remaining
    const remaining = response.headers.get("x-ratelimit-remaining");
    if (remaining) {
        const remainingNum = parseInt(remaining, 10);
        if (!isNaN(remainingNum)) {
            info.remaining = remainingNum;
        }
    }
    return info;
}
// Configuration for paths
