            const inputHeaders = new Headers(init?.headers ?? {});
            const mergedHeaders = new Headers();
            builtHeaders.forEach((value, key) => {
                mergedHeaders.set(key, value);
            });
            inputHeaders.forEach((value, key) => {
                mergedHeaders.set(key, value);
            });
            // Retry loop for rate limiting (429)
            let retries = 0;
